import React, { useState } from "react";
import "./App.css";

function App() {

  const [destination, setDestination] = useState("");
  const [budget, setBudget] = useState(50000);
  const [days, setDays] = useState(3);
  const [travelers, setTravelers] = useState(1);

  const [result, setResult] = useState(null);

  const sendQuery = async () => {

    try {

      const response = await fetch("http://127.0.0.1:8000/travel", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },

        body: JSON.stringify({
          destination: destination,
          budget: Number(budget),
          days: Number(days),
          travelers: Number(travelers)
        })
      });

      const data = await response.json();

      console.log(data);

      setResult(data);

    } catch (error) {

      console.log(error);

      alert("Backend connection failed");

    }
  };

  return (
    <div className="App">

      <h1>🇮🇳 India AI Travel Planner</h1>

      <p>
        Plan your budget-friendly India trip with AI recommendations,
        nearby places, safety analysis and smart itinerary planning.
      </p>

      <input
        type="text"
        placeholder="Enter destination"
        value={destination}
        onChange={(e) => setDestination(e.target.value)}
      />

      <br /><br />

      <input
        type="number"
        placeholder="Enter Budget"
        value={budget}
        onChange={(e) => setBudget(e.target.value)}
      />

      <br /><br />

      <input
        type="number"
        placeholder="Number of Days"
        value={days}
        onChange={(e) => setDays(e.target.value)}
      />

      <br /><br />

      <input
        type="number"
        placeholder="Number of Travelers"
        value={travelers}
        onChange={(e) => setTravelers(e.target.value)}
      />

      <br /><br />

      <button onClick={sendQuery}>
        Plan Trip
      </button>

      {result && (

        <div style={{ marginTop: "30px" }}>

          <h2>🤖 AI Response</h2>
          <p>{result.ai_response}</p>

          <h2>💰 Budget Details</h2>

          <p>🏨 Hotel Cost: ₹{result.budget?.hotel}</p>
          <p>🍛 Food Cost: ₹{result.budget?.food}</p>
          <p>🚌 Transport Cost: ₹{result.budget?.transport}</p>
          <p>📦 Misc Cost: ₹{result.budget?.misc}</p>
          <p><b>Total Budget: ₹{result.budget?.total}</b></p>

          <h2>📍 Nearby Recommended Places</h2>

          <ul>
            {result.places?.map((place, index) => (
              <li key={index}>{place}</li>
            ))}
          </ul>

          <h2>🛡 Safety Information</h2>

          <p>
            Women Safety: {result.safety?.women_safety}
          </p>

          <p>
            Child Friendly: {result.safety?.child_friendly}
          </p>

          <p>
            Night Travel Risk: {result.safety?.night_travel_risk}
          </p>

          <h2>🗓 Trip Itinerary</h2>

          <ul>
            {result.itinerary?.map((day, index) => (
              <li key={index}>{day}</li>
            ))}
          </ul>

        </div>

      )}

    </div>
  );
}

export default App;
